#!/usr/bin/env node

import fs from 'fs';
import path from 'path';

const repoRoot = path.resolve(path.dirname(new URL(import.meta.url).pathname), '..');
const templateDir = path.join(repoRoot, 'tools', 'starter-template');
const outFile = path.join(repoRoot, 'tools', 'starter-bundle.generated.js');

function walk(dir) {
  const out = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) out.push(...walk(full));
    else out.push(full);
  }
  return out;
}

if (!fs.existsSync(templateDir)) {
  console.error('Missing template directory:', templateDir);
  process.exit(1);
}

const files = walk(templateDir).sort().map((fullPath) => {
  const rel = path.relative(templateDir, fullPath).replaceAll(path.sep, '/');
  const data = fs.readFileSync(fullPath);
  return {
    path: rel,
    encoding: 'base64',
    content: data.toString('base64')
  };
});

const generated = `// Auto-generated by tools/build-starter-bundle.js\n` +
  `export const STARTER_BUNDLE_VERSION = ${JSON.stringify(new Date().toISOString())};\n` +
  `export const STARTER_BUNDLE_FILES = ${JSON.stringify(files, null, 2)};\n`;

fs.writeFileSync(outFile, generated, 'utf8');
console.log(`Generated ${path.relative(repoRoot, outFile)} with ${files.length} files.`);
